    // MARK: - Ported Turf.js buffer tests

    private func runTurfTest(name: String, result: MultiPolygon) throws {
        let (expected, tolerance) = try Self.expectedArea(name)
        let actual = result.polygons.reduce(0) { $0 + $1.area }
        let ratio = expected > 0 ? actual / expected : (actual == 0 ? 1 : 0)
        #expect(ratio > 1.0 - tolerance && ratio < 1.0 + tolerance,
                "\(name): ratio \(ratio) outside [\(1 - tolerance), \(1 + tolerance)], actual=\(actual), expected=\(expected)")
    }

    private struct TurfFixture: Sendable {
        let name: String
        let loadFeatureCollection: Bool
        let loadGeometryCollection: Bool
        let unionType: BufferUnionType

        init(name: String,
             loadFeatureCollection: Bool = false,
             loadGeometryCollection: Bool = false,
             unionType: BufferUnionType = .individual
        ) {
            self.name = name
            self.loadFeatureCollection = loadFeatureCollection
            self.loadGeometryCollection = loadGeometryCollection
            self.unionType = unionType
        }
    }

    private static let turfFixtures: [TurfFixture] = [
        .init(name: "feature-collection-points", loadFeatureCollection: true),
        .init(name: "geometry-collection-points", loadGeometryCollection: true),
        .init(name: "linestring"),
        .init(name: "multi-linestring"),
        .init(name: "multi-point"),
        .init(name: "multi-polygon"),
        .init(name: "point"),
        .init(name: "polygon-with-holes"),
        .init(name: "northern-polygon"),
        .init(name: "north-latitude-points", unionType: .overlapping),

        // Buffer around a simple polygon produces incorrect shape;
        // buffered circles at extreme points fall outside the polygon.
        .init(name: "issue-#783", loadFeatureCollection: true),
        // Buffering polygons yields a radius that's too small;
        // point buffers are correct (Ecuador variant).
        .init(name: "issue-#801-Ecuador", loadFeatureCollection: true),
        // Buffering polygons yields a radius that's too small;
        // point buffers are correct.
        .init(name: "issue-#801", loadFeatureCollection: true),
        // Buffer on a LineString has non-uniform stroke-width;
        // width varies along the line.
        .init(name: "issue-#815"),
        // Buffer that touches itself merges into a single area
        // instead of creating a hole.
        .init(name: "issue-#916", loadFeatureCollection: true),
    ]

    // Validates buffer against ported Turf.js fixture test cases.
    @Test(arguments: turfFixtures)
    private func turfFixture(_ fixture: TurfFixture) async throws {
        let params = try Self.bufferParams(fixture.name)
        let geoJson: GeoJson
        if fixture.loadGeometryCollection {
            geoJson = try TestData.geometryCollection(package: "Buffer/in", name: fixture.name)
        }
        else if fixture.loadFeatureCollection {
            geoJson = try TestData.featureCollection(package: "Buffer/in", name: fixture.name)
        }
        else {
            geoJson = try TestData.feature(package: "Buffer/in", name: fixture.name)
        }
        try runTurfTest(
            name: fixture.name,
            result: try #require(geoJson.buffered(
                by: params.distance,
                unionType: fixture.unionType,
                steps: params.steps)))
    }

    // Buffering a long LineString creates kinks / self-intersection artifacts.
    // Validates buffer on a long line that produces kinks and self-intersection artifacts.
    @Test
    func issue900() async throws {
        let params = try Self.bufferParams("issue-#900")
        try runTurfTest(
            name: "issue-#900",
            result: try #require(TestData.feature(
                package: "Buffer/in",
                name: "issue-#900")
                .buffered(
                    by: params.distance,
                    steps: params.steps)))
    }

    // MARK: - gridSize

    // Validates that `buffered(gridSize:)` matches manual pre-snapping.
    @Test
    func bufferWithGridSize() async throws {
        let polygon = try #require(Polygon([[
            Coordinate3D(latitude: 0.0001, longitude: 0.0001),
            Coordinate3D(latitude: 10.0001, longitude: 0.0001),
            Coordinate3D(latitude: 10.0001, longitude: 10.0001),
            Coordinate3D(latitude: 0.0001, longitude: 10.0001),
            Coordinate3D(latitude: 0.0001, longitude: 0.0001),
        ]]))
        let gridSize = 0.001

        let withParam = try #require(polygon.buffered(by: 100_000.0, gridSize: gridSize))
        let snapped = polygon.snappedToGrid(tolerance: gridSize)
        let manual = try #require(snapped.buffered(by: 100_000.0))
        #expect(abs(withParam.area - manual.area) < 1.0)
    }

    // MARK: - Antimeridian tests

    // Validates buffer around a point near the antimeridian stays within valid coordinate bounds.
    @Test
    func bufferedPointAntimeridian() async throws {
        let point = Point(Coordinate3D(latitude: 0.0, longitude: 179.0))
        let result = try #require(point.buffered(by: 200_000.0))
        #expect(!result.polygons.contains(where: { $0.crossesAntimeridian }))
        for poly in result.polygons {
            for coord in poly.allCoordinates {
                #expect(coord.longitude >= -180.0 && coord.longitude <= 180.0, "lon=\(coord.longitude)")
            }
        }
        for poly in result.polygons {
            for coord in poly.allCoordinates {
                #expect(coord.latitude >= -90.0 && coord.latitude <= 90.0, "lat=\(coord.latitude)")
            }
        }
        let area = result.polygons.reduce(0.0) { $0 + $1.area }
        let expected = Double.pi * 200_000.0 * 200_000.0
        #expect(area > expected * 0.1 && area < expected * 10.0)
    }

    // Validates buffer around a line crossing the antimeridian produces multiple non-crossing polygons.
    @Test
    func bufferedLineAntimeridian() async throws {
        let lineString = try #require(LineString([
            Coordinate3D(latitude: 0.0, longitude: 170.0),
            Coordinate3D(latitude: 0.0, longitude: -170.0),
        ]))
        let result = try #require(lineString.buffered(by: 100_000.0))
        #expect(!result.polygons.contains(where: { $0.crossesAntimeridian }))
        #expect(result.polygons.count >= 2)
    }

